mapper.select:


    nd.del_flag = '0'
     and nd.production_year = #{productionYear}
     and nd.batch_id = #{batchId}
     and nd.product = #{product}
     and nd.task_no like concat('%', #{taskNo}, '%')
     and nd.task_name like concat('%', #{taskName}, '%')
     and nd.problem_no like concat('%', #{problemNo}, '%')
     and nd.problem_level = #{problemLevel}
     and nd.current_status = #{currentStatus}
     and nd.schedule_status = #{scheduleStatus}
     and nd.whether_defect = #{whetherDefect}
     and nd.whether_overtime = #{whetherOvertime}
     and nd.whether_pro_recurrence = #{whetherProRecurrence}
     and nd.whether_att_required = #{whetherAttRequired}
     and nd.solution_time_over_one_day = #{solutionTimeOverOneDay}
     and uc.nick_name like concat('%', #{creatorName}, '%')
     and nd.submit_date >= #{submitDateStart}
     and nd.submit_date <= #{submitDateEnd}
     and nd.create_time >= #{createDateStart}
     and nd.create_time <= concat(#{createDateEnd}, ' 23:59:59')

        and (nd.dept_id = #{deptId}
             or nd.dept_id in (select dept_id from sys_dept where find_in_set(#{deptId}, ancestors) > 0))


order by nd.create_time desc, nd.problem_id desc

select count(1) from pm_nobatch_prolist_defect
where problem_no = #{problemNo} and del_flag = '0'
 and problem_id != #{problemId}
